window.COURSE_LANG = window.COURSE_LANG || {};
window.COURSE_LANG["esthetician"] = window.COURSE_LANG["esthetician"] || {};
window.COURSE_LANG["esthetician"]["es"] = [
  {"id":1,"q":"La desinfección se diferencia de la esterilización porque la desinfección:","opts":["Mata la mayoría de patógenos pero no necesariamente todas las esporas bacterianas","Destruye toda forma microbiana, incluidas las esporas bacterianas","Solo elimina la suciedad visible","Es lo mismo que la limpieza"],"re":"La desinfección mata la mayoría de los microorganismos patógenos pero no destruye con seguridad las esporas bacterianas; la esterilización destruye toda forma microbiana."},
  {"id":2,"q":"Antes de poder desinfectar un implemento de uso múltiple, primero hay que:","opts":["Dejarlo secar al aire toda la noche","Limpiarlo para quitar la suciedad visible","Remojarlo en agua simple por una hora","Frotarlo solo con una toalla seca"],"re":"La limpieza para quitar la suciedad visible debe ir antes de la desinfección, porque la suciedad protege a los microbios del desinfectante."},
  {"id":3,"q":"El desinfectante líquido usado en los implementos de estética debe ser:","opts":["Cualquier limpiador doméstico","Perfumado para tapar olores","Registrado por la EPA para uso en salones","Una simple solución de jabón"],"re":"Los implementos deben desinfectarse con un desinfectante registrado por la EPA; el jabón común o los limpiadores domésticos no bastan."},
  {"id":4,"q":"La mayoría de los desinfectantes líquidos registrados por la EPA para inmersión requieren contacto total durante al menos:","opts":["30 segundos","2 minutos","2 horas","10 minutos"],"re":"Los desinfectantes de inmersión estándar registrados por la EPA requieren contacto total durante al menos 10 minutos para ser eficaces."},
  {"id":5,"q":"Un artículo poroso de un solo uso, como un palillo de madera, debe:","opts":["Limpiarse y reutilizarse con el siguiente cliente","Desecharse después de un solo uso","Desinfectarse y guardarse","Remojarse en alcohol y reutilizarse"],"re":"Los artículos porosos de un solo uso no pueden desinfectarse bien y deben desecharse tras un solo uso."},
  {"id":6,"q":"Si un implemento entra en contacto con sangre o fluido corporal, debes:","opts":["Seguir usándolo con normalidad","Enjuagarlo rápido bajo el agua","Desinfectar los artículos no porosos y desechar los de un solo uso","Limpiarlo con una toalla"],"re":"Tras contacto con sangre o fluido corporal, los artículos de un solo uso se desechan y las herramientas reutilizables no porosas se limpian y desinfectan."},
  {"id":7,"q":"¿Con qué frecuencia se debe cambiar normalmente una solución desinfectante de inmersión?","opts":["Una vez al mes","Una vez a la semana","Solo cuando se ve sucia","A diario, o antes si se contamina"],"re":"La solución desinfectante debe reemplazarse a diario, o de inmediato si se contamina visiblemente, para seguir siendo eficaz."},
  {"id":8,"q":"La forma más eficaz de prevenir la propagación de infecciones en la sala de tratamiento es:","opts":["El lavado de manos adecuado","Quemar incienso","Abrir una ventana","Usar perfume"],"re":"El lavado de manos minucioso y frecuente es la medida más eficaz para prevenir la propagación de infecciones."},
  {"id":9,"q":"Los guantes desechables deben:","opts":["Usarse todo el día para ahorrar material","Lavarse y reutilizarse","Cambiarse para cada cliente","Usarse solo cuando convenga"],"re":"Los guantes desechables son de un solo uso; hay que usar un par nuevo con cada cliente para evitar la contaminación cruzada."},
  {"id":10,"q":"La capa más externa de la epidermis es el:","opts":["Estrato granuloso","Estrato espinoso","Estrato basal","Estrato córneo"],"re":"El estrato córneo es la capa epidérmica más externa, formada por células muertas aplanadas y llenas de queratina."},
  {"id":11,"q":"Las nuevas células de la epidermis se producen principalmente en el:","opts":["Estrato basal (germinativo)","Estrato córneo","Estrato lúcido","Dermis"],"re":"La división celular que produce nuevos queratinocitos ocurre en el estrato basal, la capa epidérmica más profunda."},
  {"id":12,"q":"La melanina, el pigmento que ayuda a proteger la piel de los rayos UV, es producida por:","opts":["Los fibroblastos","Los melanocitos","Las glándulas sudoríparas","Las glándulas sebáceas"],"re":"Los melanocitos del estrato basal producen melanina, que absorbe la luz UV y ayuda a proteger las células más profundas."},
  {"id":13,"q":"El colágeno y la elastina, que dan fuerza y elasticidad a la piel, se encuentran principalmente en la:","opts":["Epidermis","Estrato córneo","Tallo del pelo","Dermis"],"re":"La dermis contiene fibras de colágeno y elastina, producidas por los fibroblastos, que dan resistencia y elasticidad."},
  {"id":14,"q":"La capa más profunda de la piel, formada en gran parte por grasa para aislar y amortiguar, es la:","opts":["Capa subcutánea (hipodermis)","Epidermis","Capa papilar","Estrato granuloso"],"re":"La capa subcutánea (hipodermis) está bajo la dermis y se compone en gran parte de grasa para aislar y absorber impactos."},
  {"id":15,"q":"El sebo (grasa) que lubrica la piel es producido por las:","opts":["Glándulas sudoríparas","Glándulas sebáceas","El músculo erector del pelo","Los melanocitos"],"re":"Las glándulas sebáceas secretan sebo, la sustancia grasa que lubrica la piel y el pelo."},
  {"id":16,"q":"Un punto negro (comedón abierto) se ve oscuro principalmente porque:","opts":["Contiene sangre seca","Es una colonia de bacterias","El sebo atrapado se oxida al contacto con el aire","La suciedad penetró en la piel"],"re":"Un comedón abierto se ve oscuro porque el sebo y las células atrapadas se oxidan al exponerse al aire, no por suciedad."},
  {"id":17,"q":"La escala de Fitzpatrick se usa para clasificar la piel según su:","opts":["Reacción a la luz UV y tendencia a quemarse o broncearse","Grasa y tamaño de poros","Grosor en milímetros","Número de glándulas sudoríparas"],"re":"La escala de Fitzpatrick (tipos I–VI) clasifica la piel según cómo reacciona a la exposición UV y su tendencia a quemarse o broncearse."},
  {"id":18,"q":"El pequeño músculo que se contrae para dar 'piel de gallina' y está unido a un folículo piloso es el:","opts":["Fibroblasto","Erector del pelo (arrector pili)","Conducto sebáceo","Glándula sudorípara"],"re":"El músculo erector del pelo se une al folículo piloso y se contrae para erizar el pelo, causando la piel de gallina."},
  {"id":19,"q":"El movimiento suave y deslizante que se usa para empezar y terminar un masaje facial es:","opts":["Tapotement","Petrissage","Effleurage","Fricción"],"re":"El effleurage es un movimiento suave y deslizante que se usa para empezar y terminar el masaje y calentar el tejido."},
  {"id":20,"q":"El movimiento de masaje que amasa, levanta y aprieta el tejido se llama:","opts":["Effleurage","Tapotement","Vibración","Petrissage"],"re":"El petrissage es un movimiento de amasado que levanta, aprieta y presiona el tejido para estimular la circulación profunda."},
  {"id":21,"q":"El movimiento de masaje de golpeteo o percusión ligera se llama:","opts":["Effleurage","Tapotement","Fricción","Petrissage"],"re":"El tapotement es un movimiento rápido de golpeteo o percusión que estimula y vigoriza la piel."},
  {"id":22,"q":"Un beneficio general del masaje facial es que:","opts":["Elimina las arrugas de forma permanente","Reemplaza la necesidad de limpiar la piel","Aumenta la circulación y ayuda a relajar los músculos","Aclara el pigmento de la piel"],"re":"El masaje facial aumenta la circulación sanguínea y relaja los músculos faciales, llevando oxígeno y nutrientes a la piel."},
  {"id":23,"q":"Durante un facial, la extracción manual de comedones debe hacerse:","opts":["Con las uñas desnudas","De forma agresiva para ahorrar tiempo","Antes de limpiar la piel","Solo tras ablandar la piel y con la técnica adecuada"],"re":"Las extracciones deben hacerse tras ablandar la piel (vapor o toallas tibias) y con técnica suave y adecuada para evitar traumatismos y cicatrices."},
  {"id":24,"q":"La desincrustación galvánica, que ablanda y emulsiona el sebo, actúa en el:","opts":["Polo negativo, creando una reacción alcalina","Polo positivo, volviendo ácido el producto","Solo en la superficie de la piel","Ajuste de corriente más alto posible"],"re":"La desincrustación usa el polo negativo para crear una reacción alcalina que ablanda y emulsiona el sebo en los folículos."},
  {"id":25,"q":"La corriente de alta frecuencia está generalmente contraindicada para un cliente que:","opts":["Tiene piel normal","Usa lentes de contacto","Tiene marcapasos o está embarazada","Tiene piel seca"],"re":"La alta frecuencia (y la galvánica) está contraindicada para clientes embarazadas o con marcapasos, entre otras condiciones."},
  {"id":26,"q":"El masaje facial debe evitarse generalmente sobre:","opts":["Piel sana e intacta","La frente","Las mejillas","Piel inflamada, lesionada o infectada"],"re":"El masaje está contraindicado sobre piel inflamada, lesionada o infectada porque puede propagar infección o empeorar la irritación."},
  {"id":27,"q":"Para evitar contaminar el recipiente de cera, el esteticista debe:","opts":["Nunca hacer doble inmersión con el aplicador","Reutilizar el mismo palillo varias veces (doble inmersión)","Revolver la cera con los dedos","Compartir palillos entre clientes"],"re":"La doble inmersión reintroduce bacterias en la cera; usa un aplicador nuevo cada vez que vuelvas al recipiente."},
  {"id":28,"q":"La depilación con cera está contraindicada para un cliente que toma isotretinoína (Accutane) porque la piel:","opts":["Está demasiado grasa para sujetar la cera","Está frágil y puede levantarse o desgarrarse","No produce pelo","Es inmune a la irritación"],"re":"La isotretinoína adelgaza y fragiliza la piel, por lo que la cera puede levantarla o desgarrarla y causar cicatrices; debe evitarse."},
  {"id":29,"q":"Antes de aplicar cera blanda en una zona grande, debes:","opts":["Aplicarla lo más caliente posible","Saltarte la limpieza de la piel","Aplicarla en contra del crecimiento del pelo","Probar primero la temperatura de la cera en ti mismo"],"re":"Prueba siempre la temperatura de la cera (en tu muñeca o antebrazo) antes de aplicarla a un cliente para evitar quemaduras."},
  {"id":30,"q":"La cera blanda (de banda) suele aplicarse en la dirección del crecimiento del pelo y se retira:","opts":["En contra de la dirección del crecimiento","En la misma dirección del crecimiento","Recto hacia arriba, alejándose de la piel","Solo con pinzas"],"re":"La cera blanda se extiende a favor del crecimiento y la banda se retira en contra del crecimiento, pegada a la piel."},
  {"id":31,"q":"¿Qué zona NO es generalmente apropiada para depilar con cera?","opts":["Las cejas","Piel con irritación activa, quemadura solar o lesiones abiertas","Las piernas","El labio superior"],"re":"La cera está contraindicada sobre piel irritada, quemada por el sol o lesionada, porque puede causar lesiones."},
  {"id":32,"q":"Un cliente debe evitar el sol o el bronceado de la zona justo después de depilarse porque la piel está:","opts":["Permanentemente oscurecida","Incapaz de sudar","Temporalmente sensible y más propensa a la irritación","Sin poder broncearse"],"re":"La piel recién depilada está temporalmente sensible y más propensa a la irritación y a la hiperpigmentación por el sol."},
  {"id":33,"q":"Las pinzas y la cera eliminan el pelo desde:","opts":["La raíz (por debajo de la superficie de la piel)","Solo la punta del pelo","Solo la superficie de la piel","La glándula sebácea"],"re":"Las pinzas, la cera y el sugaring eliminan el pelo desde la raíz, por lo que el rebrote tarda más que con el afeitado."},
  {"id":34,"q":"Después de la cera, la zona tratada debe calmarse con un producto que sea:","opts":["Un exfoliante áspero","Una loción antiséptica suave y calmante","Una fragancia fuerte","Un ungüento que da calor"],"re":"Un producto post-cera suave, calmante y antiséptico calma la piel y ayuda a prevenir la irritación y la infección."},
  {"id":35,"q":"Los alfa hidroxiácidos (AHA), como el ácido glicólico, se usan en el cuidado de la piel principalmente para:","opts":["Agregar grasa a la piel seca","Adormecer la piel","Exfoliar aflojando las células muertas de la superficie","Oscurecer el tono de la piel"],"re":"Los AHA son exfoliantes químicos solubles en agua que aflojan la unión entre las células muertas superficiales y alisan la piel."},
  {"id":36,"q":"El ácido salicílico (un BHA) es especialmente útil para la piel grasa y propensa al acné porque es:","opts":["Soluble en agua y se queda en la superficie","Un oclusivo que sella el poro","Un exfoliante físico","Soluble en grasa y puede penetrar en el poro"],"re":"El ácido salicílico es soluble en grasa, por lo que puede penetrar en los poros llenos de sebo y ayudar a limpiarlos, a diferencia de los AHA solubles en agua."},
  {"id":37,"q":"Un humectante como la glicerina funciona al:","opts":["Formar una barrera grasa sobre la piel","Exfoliar las células muertas","Atraer y fijar el agua a la piel","Matar bacterias"],"re":"Los humectantes como la glicerina atraen y fijan el agua, ayudando a atraer y retener la humedad en la piel."},
  {"id":38,"q":"Un ingrediente oclusivo (por ejemplo, la petrolato/vaselina) ayuda a la piel al:","opts":["Formar una barrera que reduce la pérdida de agua","Atraer agua del aire","Disolver las células muertas","Bajar el pH de la piel"],"re":"Los oclusivos forman una barrera en la superficie que reduce la pérdida de agua transepidérmica, ayudando a retener la humedad."},
  {"id":39,"q":"Para proteger contra los rayos UVA y UVB, un protector solar debe estar etiquetado como:","opts":["A base de agua","De amplio espectro","Sin fragancia","Sin aceite"],"re":"La etiqueta 'amplio espectro' significa que el protector solar protege contra la radiación UVA y UVB."},
  {"id":40,"q":"Como la exfoliación química aumenta la sensibilidad al sol, siempre se debe aconsejar a los clientes que:","opts":["Eviten lavarse la cara","Dejen de beber agua","Exfolien el doble de seguido","Usen a diario un protector solar de amplio espectro"],"re":"La piel exfoliada es más sensible a la luz UV, por lo que el protector solar diario de amplio espectro es esencial para prevenir daños."},
  {"id":41,"q":"En la escala de pH, un valor de 7 se considera:","opts":["Neutro","Fuertemente ácido","Fuertemente alcalino","Imposible para productos de piel"],"re":"Un pH de 7 es neutro; los valores por debajo de 7 son ácidos y los que están por encima de 7 son alcalinos."},
  {"id":42,"q":"Un emoliente en una crema hidratante funciona principalmente para:","opts":["Quitar la grasa de la piel","Subir el pH de la piel","Suavizar y alisar la superficie de la piel","Exfoliar las células muertas"],"re":"Los emolientes suavizan y alisan la piel rellenando los huecos entre las células superficiales, mejorando la textura y la comodidad."},
  {"id":43,"q":"En California, el ámbito de práctica de un esteticista se limita generalmente a trabajar sobre:","opts":["El tejido muscular y nervioso","La superficie de la piel (epidermis), no el tejido vivo debajo","El torrente sanguíneo","La estructura ósea"],"re":"Un esteticista en California puede trabajar sobre la superficie de la piel y no puede afectar el tejido vivo por debajo de la epidermis."},
  {"id":44,"q":"En California, a un esteticista NO se le permite:","opts":["Hacer faciales","Depilar vello no deseado con cera","Aplicar maquillaje","Inyectar Botox o rellenos dérmicos"],"re":"Las inyecciones como el Botox y los rellenos dérmicos quedan fuera del ámbito de un esteticista; solo los profesionales médicos autorizados pueden inyectar."},
  {"id":45,"q":"¿Qué aparato NO puede operar un esteticista en California?","opts":["Un láser médico","Un vaporizador facial","Una varita de alta frecuencia","Una lámpara de aumento"],"re":"Los esteticistas no pueden operar láseres médicos ni aparatos que penetren por debajo de la epidermis; eso requiere una licencia médica."},
  {"id":46,"q":"Una licencia de esteticista vigente debe:","opts":["Guardarse en casa para protegerla","Mostrarse solo si se pide","Exhibirse donde los clientes puedan verla","Plastificarse y guardarse"],"re":"California exige que los licenciatarios exhiban su licencia vigente a la vista del público en su lugar de trabajo."},
  {"id":47,"q":"Una Hoja de Datos de Seguridad (SDS) de un producto sirve para:","opts":["Fijar el precio de venta del producto","Proporcionar información de peligros, manejo y primeros auxilios","Listar a los competidores del fabricante","Anunciar el producto"],"re":"Una SDS proporciona información de seguridad, incluidos peligros, manejo seguro, almacenamiento y primeros auxilios de un producto."},
  {"id":48,"q":"Los peelings químicos que realiza un esteticista en California deben ser:","opts":["Peelings profundos de grado médico","De cualquier intensidad que el cliente pida","Inyectados en la dermis","Peelings superficiales que afectan solo la epidermis"],"re":"Los esteticistas solo pueden hacer peelings superficiales (ligeros) que actúan sobre la epidermis; los más profundos requieren un profesional médico."},
  {"id":49,"q":"Para verificar si un profesional del cuidado de la piel tiene licencia vigente, un cliente puede:","opts":["Consultar los registros de licencias en línea de la junta estatal","Preguntarle a un vecino","Suponer que todos en un salón tienen licencia","Mirar el letrero del salón"],"re":"El estado de la licencia puede verificarse en la búsqueda de licencias en línea de la Junta de Barbería y Cosmetología de California."},
  {"id":50,"q":"Si un cliente dice sentirse débil o tiene una reacción adversa durante un servicio, el esteticista debe primero:","opts":["Continuar el servicio rápidamente","Ignorarlo a menos que se desmaye","Detener el servicio y atender la seguridad del cliente","Salir de la sala"],"re":"La seguridad del cliente es lo primero: detén el servicio, evalúa al cliente y busca ayuda médica si es necesario."}
];
